import{_ as e,o as i,c as t,ai as o}from"./chunks/framework.BIXs0jTs.js";const r="/assets/preface-cover.Balx8Fq4.png",k=JSON.parse('{"title":"Skill 设计模式与最佳实践","description":"","frontmatter":{"title":"Skill 设计模式与最佳实践"},"headers":[],"relativePath":"20-skill/design-patterns.md","filePath":"20-skill/design-patterns.md","lastUpdated":null}'),a={name:"20-skill/design-patterns.md"};function s(n,l,d,c,p,g){return i(),t("div",null,[...l[0]||(l[0]=[o('<h1 id="第-6-章-skill-设计模式与最佳实践" tabindex="-1">第 6 章　Skill 设计模式与最佳实践 <a class="header-anchor" href="#第-6-章-skill-设计模式与最佳实践" aria-label="Permalink to &quot;第 6 章　Skill 设计模式与最佳实践&quot;">​</a></h1><p><img src="'+r+'" alt="Skill 设计模式：常见架构与最佳实践"></p><p>在第 5 章中，我们实现了一个简单的 <code>generate_commit_message</code> Skill。这就像学会了写“Hello World”函数。但在真实的工程体系中，Skill 往往需要处理更复杂的逻辑：多步推理、错误重试、条件分支等。</p><p>本章将介绍几种成熟的 <strong>Skill 设计模式</strong>。这些模式源自软件工程中的经典设计模式（如管道、策略、适配器），经过改造后，非常适合用于构建稳定、强大的 AI 能力。</p><h2 id="_6-1-skill-设计的-三层模型" tabindex="-1">6.1 Skill 设计的“三层模型” <a class="header-anchor" href="#_6-1-skill-设计的-三层模型" aria-label="Permalink to &quot;6.1 Skill 设计的“三层模型”&quot;">​</a></h2><p>在开始具体模式之前，我们先统一一下 Skill 的架构视图。一个健壮的 Skill 通常包含三个层次：</p><ol><li><p><strong>接口层 (Interface Layer)</strong>：</p><ul><li>定义 <code>inputs</code>（参数）和 <code>outputs</code>（返回值）。</li><li>负责参数的校验和默认值填充。</li><li><em>类比：API 的 Controller 层。</em></li></ul></li><li><p><strong>逻辑层 (Logic Layer / Prompt Strategy)</strong>：</p><ul><li>决定如何组织 Prompt。</li><li>决定是否需要分步骤调用 AI（Chain of Thought）。</li><li>决定如何解析 AI 的原始回复。</li><li><em>类比：Service 层。</em></li></ul></li><li><p><strong>能力层 (Capability Layer)</strong>：</p><ul><li>实际执行动作的地方（读文件、调 API、运行命令）。</li><li>这一层往往依赖底层的 Claude Code 内置工具或 MCP 工具。</li><li><em>类比：DAO / Infrastructure 层。</em></li></ul></li></ol><p>设计 Skill 时，<strong>逻辑层</strong>是我们可以发挥最大创造力的地方。</p><hr><h2 id="_6-2-常见-skill-设计模式" tabindex="-1">6.2 常见 Skill 设计模式 <a class="header-anchor" href="#_6-2-常见-skill-设计模式" aria-label="Permalink to &quot;6.2 常见 Skill 设计模式&quot;">​</a></h2><h3 id="_6-2-1-管道模式-the-pipeline" tabindex="-1">6.2.1 管道模式 (The Pipeline) <a class="header-anchor" href="#_6-2-1-管道模式-the-pipeline" aria-label="Permalink to &quot;6.2.1 管道模式 (The Pipeline)&quot;">​</a></h3><p><strong>适用场景</strong>：任务可以被拆分为线性步骤，每一步的输出是下一步的输入。</p><p><strong>案例</strong>：<code>refactor_module</code>（模块重构）</p><ol><li><strong>Step 1 (Analyze)</strong>：读取旧代码 -&gt; 输出重构计划（JSON）。</li><li><strong>Step 2 (Implement)</strong>：读取重构计划 -&gt; 输出新代码。</li><li><strong>Step 3 (Verify)</strong>：运行测试 -&gt; 输出测试报告。</li></ol><p><strong>Prompt 设计要点</strong>：</p><ul><li>显式要求 AI 在 Step 1 输出结构化数据（如 JSON），以便 Step 2 精确读取，避免“幻觉”传递。</li></ul><h3 id="_6-2-2-路由模式-the-router" tabindex="-1">6.2.2 路由模式 (The Router) <a class="header-anchor" href="#_6-2-2-路由模式-the-router" aria-label="Permalink to &quot;6.2.2 路由模式 (The Router)&quot;">​</a></h3><p><strong>适用场景</strong>：用户的一个意图可能对应多种不同的处理路径。</p><p><strong>案例</strong>：<code>analyze_log</code>（日志分析）</p><ul><li>输入是一段日志。</li><li>Skill 内部先进行一次快速判断（分类）： <ul><li>如果是 <strong>SQL 错误</strong> -&gt; 调用 <code>sql_debugger</code> 子流程。</li><li>如果是 <strong>前端构建错误</strong> -&gt; 调用 <code>webpack_fixer</code> 子流程。</li><li>如果是 <strong>权限错误</strong> -&gt; 提示检查 IAM 配置。</li></ul></li></ul><p><strong>Prompt 设计要点</strong>：</p><ul><li>第一个 Prompt 专注于“分类”，不要尝试直接解决问题，输出类别标签即可。</li></ul><h3 id="_6-2-3-验证器模式-the-validator-self-correction" tabindex="-1">6.2.3 验证器模式 (The Validator / Self-Correction) <a class="header-anchor" href="#_6-2-3-验证器模式-the-validator-self-correction" aria-label="Permalink to &quot;6.2.3 验证器模式 (The Validator / Self-Correction)&quot;">​</a></h3><p><strong>适用场景</strong>：对输出的准确性要求极高（如生成 SQL、正则、JSON 配置）。</p><p><strong>案例</strong>：<code>generate_sql</code></p><ol><li><strong>Generate</strong>：根据自然语言生成 SQL。</li><li><strong>Validate</strong>：在一个沙盒环境或通过 <code>EXPLAIN</code> 命令检查 SQL 语法。</li><li><strong>Correct</strong>：如果验证失败，将错误信息喂回给 AI：“你生成的 SQL 报错了，错误是...，请修正。”</li></ol><p><strong>Prompt 设计要点</strong>：</p><ul><li>这是一个循环结构。需要设置最大重试次数（如 3 次），防止无限死循环。</li></ul><hr><h2 id="_6-3-skill-的组合与嵌套" tabindex="-1">6.3 Skill 的组合与嵌套 <a class="header-anchor" href="#_6-3-skill-的组合与嵌套" aria-label="Permalink to &quot;6.3 Skill 的组合与嵌套&quot;">​</a></h2><p>就像函数可以调用函数一样，Skill 也可以调用 Skill。</p><h3 id="_6-3-1-原子-skill-vs-复合-skill" tabindex="-1">6.3.1 原子 Skill vs. 复合 Skill <a class="header-anchor" href="#_6-3-1-原子-skill-vs-复合-skill" aria-label="Permalink to &quot;6.3.1 原子 Skill vs. 复合 Skill&quot;">​</a></h3><ul><li><strong>原子 Skill</strong>：只做一件事，不仅 Prompt 简单，而且容易测试。例如 <code>read_file</code>, <code>git_diff</code>, <code>parse_json</code>.</li><li><strong>复合 Skill</strong>：通过编排多个原子 Skill 来完成业务目标。例如 <code>daily_report</code> 可能内部调用了 <code>git_log_summary</code> 和 <code>ticket_system_query</code>。</li></ul><h3 id="_6-3-2-组合的原则" tabindex="-1">6.3.2 组合的原则 <a class="header-anchor" href="#_6-3-2-组合的原则" aria-label="Permalink to &quot;6.3.2 组合的原则&quot;">​</a></h3><ul><li><strong>依赖倒置</strong>：复合 Skill 不应强依赖具体的原子 Skill 实现，而是依赖其“接口约定”。</li><li><strong>上下文传递</strong>：在 Skill 之间传递数据时，尽量清洗掉无关信息，只传核心字段，节省 Context Window。</li></ul><hr><h2 id="_6-4-skill-与团队规范的结合" tabindex="-1">6.4 Skill 与团队规范的结合 <a class="header-anchor" href="#_6-4-skill-与团队规范的结合" aria-label="Permalink to &quot;6.4 Skill 与团队规范的结合&quot;">​</a></h2><p>Skill 是推行团队规范的最佳载体。</p><h3 id="_6-4-1-风格指南即-prompt" tabindex="-1">6.4.1 风格指南即 Prompt <a class="header-anchor" href="#_6-4-1-风格指南即-prompt" aria-label="Permalink to &quot;6.4.1 风格指南即 Prompt&quot;">​</a></h3><p>不要指望开发者去读那份 50 页的《编码规范 PDF》。把规范写进 Skill 的 System Prompt 里。</p><ul><li><strong>Naming Skill</strong>：自动检查变量命名是否符合 <code>CamelCase</code> 或 <code>snake_case</code> 要求。</li><li><strong>Linting Skill</strong>：在生成代码时，强制要求 AI 遵守 Prettier 配置。</li></ul><h3 id="_6-4-2-审查清单-checklist" tabindex="-1">6.4.2 审查清单 (Checklist) <a class="header-anchor" href="#_6-4-2-审查清单-checklist" aria-label="Permalink to &quot;6.4.2 审查清单 (Checklist)&quot;">​</a></h3><p>在 <code>code_review</code> Skill 中，内置团队关注的特定风险点：</p><ul><li>“是否包含硬编码的密钥？”</li><li>“是否处理了 API 超时？”</li><li>“是否打印了敏感日志？”</li></ul><p>通过将这些检查点硬编码在 Prompt 中，Skill 成为了一个不知疲倦的、严格的审查员。</p><hr><h2 id="_6-5-小结" tabindex="-1">6.5 小结 <a class="header-anchor" href="#_6-5-小结" aria-label="Permalink to &quot;6.5 小结&quot;">​</a></h2><p>设计 Skill 不仅仅是写 Prompt，更是在设计<strong>微型软件系统</strong>。</p><ul><li>用 <strong>三层模型</strong> 隔离变化。</li><li>用 <strong>管道、路由、验证器</strong> 解决复杂逻辑。</li><li>用 <strong>组合</strong> 提高复用性。</li></ul><p>当你掌握了这些模式，你就不再只是在使用 Claude Code，而是在<strong>架构</strong>它。你的 Skill 库将变得像标准库一样可靠。</p><p>下一章，我们将把视角放大，看看如何在一个多人团队中管理和分发这些 Skill，建立真正的<strong>团队级 Skill 体系</strong>。</p>',51)])])}const u=e(a,[["render",s]]);export{k as __pageData,u as default};
